import { execSync } from "child_process";
import fs from "fs";
import { chromium } from "playwright";
function putText(n,s){const repo=process.env.GH_REPO,tok=process.env.GH_TOKEN;const url='https://api.github.com/repos/'+repo+'/contents/analize/'+n;let sha='';try{sha=JSON.parse(execSync('curl -s --max-time 30 -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||'';}catch(e){}const b={message:'x',branch:'main',content:Buffer.from(s,'utf8').toString('base64')};if(sha)b.sha=sha;fs.writeFileSync('/tmp/pf.json',JSON.stringify(b));execSync('curl -s --max-time 40 -X PUT -H "Authorization: Bearer '+tok+'" -d @/tmp/pf.json "'+url+'"',{encoding:'utf8'});}
function putBin(n,localPath){const repo=process.env.GH_REPO,tok=process.env.GH_TOKEN;const url='https://api.github.com/repos/'+repo+'/contents/analize/'+n;let sha='';try{sha=JSON.parse(execSync('curl -s --max-time 30 -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||'';}catch(e){}const content=fs.readFileSync(localPath).toString('base64');const b={message:'x',branch:'main',content:content};if(sha)b.sha=sha;fs.writeFileSync('/tmp/pb.json',JSON.stringify(b));execSync('curl -s --max-time 60 -X PUT -H "Authorization: Bearer '+tok+'" -d @/tmp/pb.json "'+url+'"',{encoding:'utf8'});}
const BASE='https://dev.avesa.lt';const U=process.env.WP_USER||'';const P=(process.env.WP_APP_PASS||'').replace(/\s+/g,'');
const F={"main": "", "ui": "", "css": "", "profilejs": ""};const SETUP="if(!defined('ABSPATH'))return;\nadd_action('wp_loaded',function(){\n  if(($_GET['ps_setup']??'')!=='1')return;\n  if(($_GET['token']??'')!=='cmplz_6680aa2a42151d54fa8d64ec')return;\n  global $wpdb;\n  // Bridge user (WP_USER) \u2014 rasti admin\n  $admin = get_user_by('login', getenv('WP_USER') ?: '');\n  if(!$admin){ $admins=get_users(array('role'=>'administrator','number'=>1)); $admin=$admins[0]??null; }\n  if(!$admin){ echo 'no admin'; exit; }\n  $uid = $admin->ID;\n  wp_set_current_user($uid);\n  // Isvalom senus test\n  $wpdb->query($wpdb->prepare(\"DELETE FROM {$wpdb->prefix}ps_pets WHERE user_id=%d AND pet_name IN ('Reksas','Murk\u0117')\", $uid));\n\n  // Reksas su pilnais duomenimis\n  $req=new WP_REST_Request('POST','/petshop/v1/pet-profile');\n  $req->set_param('species','dog');$req->set_param('pet_name','Reksas');\n  $req->set_param('life_stage','adult');$req->set_param('dog_size','large');\n  $req->set_param('primary_need','skin_allergy');$req->set_param('current_food_brand','Josera');\n  $pet_id=rest_do_request($req)->get_data()['pet_id'];\n\n  // Produktas i lentynele + refill\n  $prods=wc_get_products(array('limit'=>3,'status'=>'publish'));\n  foreach($prods as $i=>$p){\n    $reqL=new WP_REST_Request('POST','/petshop/v1/pet-product-link');\n    $reqL->set_param('pet_id',$pet_id);$reqL->set_param('product_id',$p->get_id());\n    $reqL->set_param('relationship_type',$i===0?'primary_food':'treat');\n    rest_do_request($reqL);\n  }\n  if(!empty($prods)){\n    $pid=$prods[0]->get_id();\n    $now=new DateTime('now',new DateTimeZone('UTC'));$empty=clone $now;$empty->modify('+23 days');\n    $wpdb->query($wpdb->prepare(\"DELETE FROM {$wpdb->prefix}ps_refill_tracking WHERE user_id=%d AND product_id=%d\",$uid,$pid));\n    $wpdb->insert($wpdb->prefix.'ps_refill_tracking',array('user_id'=>$uid,'product_id'=>$pid,'pet_id'=>$pet_id,'last_purchase_date'=>$now->format('Y-m-d H:i:s'),'purchase_count'=>3,'avg_interval_days'=>30,'predicted_empty_date'=>$empty->format('Y-m-d H:i:s'),'confidence'=>0.9,'status'=>'active','created_at'=>$now->format('Y-m-d H:i:s'),'updated_at'=>$now->format('Y-m-d H:i:s')));\n  }\n  // Priminimas\n  $due=new DateTime('now',new DateTimeZone('UTC'));$due->modify('+12 days');\n  $wpdb->insert($wpdb->prefix.'ps_reminders',array('user_id'=>$uid,'pet_id'=>$pet_id,'reminder_type'=>'vaccination','reminder_label'=>'Skiepai','due_date'=>$due->format('Y-m-d H:i:s'),'status'=>'active','created_at'=>$due->format('Y-m-d H:i:s'),'updated_at'=>$due->format('Y-m-d H:i:s')));\n  $due2=new DateTime('now',new DateTimeZone('UTC'));$due2->modify('+30 days');\n  $wpdb->insert($wpdb->prefix.'ps_reminders',array('user_id'=>$uid,'pet_id'=>$pet_id,'reminder_type'=>'flea_tick','reminder_label'=>'Blus\u0173 ir erki\u0173 apsauga','due_date'=>$due2->format('Y-m-d H:i:s'),'status'=>'active','created_at'=>$due2->format('Y-m-d H:i:s'),'updated_at'=>$due2->format('Y-m-d H:i:s')));\n\n  echo wp_json_encode(array('pet_id'=>$pet_id,'uid'=>$uid,'login'=>$admin->user_login));exit;\n},6);";
function api(method,path,body){const auth='-u "'+U+':'+P+'"';let cmd;if(body){fs.writeFileSync('/tmp/b.json',JSON.stringify(body));cmd='curl -s -k -A "Mozilla/5.0" --max-time 90 '+auth+' -X '+method+' -H "Content-Type: application/json" --data-binary @/tmp/b.json "'+BASE+path+'"';}else{cmd='curl -s -k -A "Mozilla/5.0" --max-time 60 '+auth+' -X '+method+' "'+BASE+path+'"';}let r;try{r=execSync(cmd,{encoding:'utf8',maxBuffer:30000000});}catch(e){r=(e.stdout||'');}return r;}
function sh(c){try{return execSync(c,{encoding:'utf8',maxBuffer:30000000});}catch(e){return (e.stdout||'')+'[ERR]';}}
(async()=>{
  let log='';const L=s=>{log+=s+'\n';};

  // Deploy
  const depPHP="if(!defined('ABSPATH'))return;\nadd_action('wp_loaded',function(){if(($_GET['ps_ud']??'')!=='1')return;if(($_GET['token']??'')!=='cmplz_6680aa2a42151d54fa8d64ec')return;$d=WP_PLUGIN_DIR.'/petshop-core';$o=array();$o['ui']=@file_put_contents($d.'/includes/class-pet-ui.php',base64_decode('"+F.ui+"'));$o['css']=@file_put_contents($d.'/assets/pet-form.css',base64_decode('"+F.css+"'));$o['pjs']=@file_put_contents($d.'/assets/pet-profile.js',base64_decode('"+F.profilejs+"'));$o['main']=@file_put_contents($d.'/petshop-core.php',base64_decode('"+F.main+"'));header('Content-Type:application/json');echo wp_json_encode($o);exit;},6);";
  const c=api('POST','/wp-json/code-snippets/v1/snippets',{name:'ProfUI Dep',desc:'x',code:depPHP,scope:'global',active:true,priority:5});
  let sid=0;try{sid=JSON.parse(c).id;}catch(e){}
  execSync('sleep 2');
  L('deploy: '+sh('curl -s -k -A "Mozilla/5.0" --max-time 30 "'+BASE+'/?ps_ud=1&token=cmplz_6680aa2a42151d54fa8d64ec"'));
  if(sid) api('POST','/wp-json/code-snippets/v1/snippets/'+sid+'/deactivate',{});

  // Setup test augintinis adminui
  const c2=api('POST','/wp-json/code-snippets/v1/snippets',{name:'ProfUI Setup',desc:'x',code:SETUP,scope:'global',active:true,priority:6});
  let sid2=0;try{sid2=JSON.parse(c2).id;}catch(e){}
  execSync('sleep 2');
  L('setup: '+sh('curl -s -k -A "Mozilla/5.0" --max-time 40 "'+BASE+'/?ps_setup=1&token=cmplz_6680aa2a42151d54fa8d64ec"'));
  if(sid2) api('POST','/wp-json/code-snippets/v1/snippets/'+sid2+'/deactivate',{});

  // Vizualus testas — login kaip admin per Playwright, atidaryti MyAccount tab
  const browser=await chromium.launch();
  const ctx=await browser.newContext({viewport:{width:1000,height:1400},ignoreHTTPSErrors:true});
  const page=await ctx.newPage();
  const errs=[];
  page.on('console',m=>{if(m.type()==='error')errs.push(m.text());});
  page.on('pageerror',e=>errs.push('PAGEERR: '+e.message));

  // WP login
  await page.goto(BASE+'/wp-login.php',{waitUntil:'domcontentloaded',timeout:60000});
  await page.fill('#user_login', U);
  await page.fill('#user_pass', P);
  await page.click('#wp-submit');
  await page.waitForTimeout(3000);

  // MyAccount augintinis tab
  await page.goto(BASE+'/my-account/augintinis/?nc='+Date.now(),{waitUntil:'domcontentloaded',timeout:60000});
  await page.waitForTimeout(4000);

  const hasProfile = await page.locator('.pspet-profile').count();
  L('pspet-profile: '+hasProfile);
  const hasName = await page.locator('.pspet-p-name').count();
  L('name block: '+hasName);
  if(hasName) L('name text: '+(await page.locator('.pspet-p-name').first().innerText()));
  const hasRing = await page.locator('.pspet-ring').count();
  L('refill ring: '+hasRing);
  const hasShelf = await page.locator('.pspet-shelf-item').count();
  L('shelf items: '+hasShelf);
  const hasTimeline = await page.locator('.pspet-tl-item').count();
  L('timeline items: '+hasTimeline);
  const hasFbPills = await page.locator('.pspet-fb-pill').count();
  L('feedback pills: '+hasFbPills);

  await page.screenshot({path:'/tmp/profile.png',fullPage:true});
  L('JS errors: '+(errs.length?errs.slice(0,5).join(' | '):'NONE'));
  await browser.close();

  putText('profile_visual.txt',log);
  putBin('profile.png','/tmp/profile.png');
})();
